}

public class FizzBuzz {
    public static void main(String[] args) {

        System.out.println("=== if-else approach ===");
        for (int i = 1; i <= 50; i++) {
            if (i % 15 == 0) {
                System.out.println("FizzBuzz");
            } else if (i % 3 == 0) {
                System.out.println("Fizz");
            } else if (i % 5 == 0) {
                System.out.println("Buzz");
            } else {
                System.out.println(i);
            }
        }

        System.out.println("=== switch expression approach ===");
        for (int i = 1; i <= 50; i++) {
            // Compute a key based on divisibility
            String key = (i % 15 == 0) ? "fb" :
                         (i % 3 == 0)  ? "f"  :
                         (i % 5 == 0)  ? "b"  : "n";

            String output = switch (key) {
                case "fb" -> "FizzBuzz";
                case "f"  -> "Fizz";
                case "b"  -> "Buzz";
                default   -> String.valueOf(i);
            };
            System.out.println(output);
        }
    }
}

public interface Shape {
    double area();
    double perimeter();

    default String describe() {
        return String.format("Shape[area=%.2f, perimeter=%.2f]", area(), perimeter());
    }
}

public abstract class AbstractShape implements Shape {
    protected final String colour;

    public AbstractShape(String colour) {
        this.colour = colour;
    }

    @Override
    public String toString() {
        return colour + " " + describe();
    }
}

public class Circle extends AbstractShape {
    private final double radius;

    public Circle(String colour, double radius) {
        super(colour);
        this.radius = radius;
    }

    @Override
    public double area() { return Math.PI * radius * radius; }

    @Override
    public double perimeter() { return 2 * Math.PI * radius; }
}

public class Rectangle extends AbstractShape {
    private final double width, height;

    public Rectangle(String colour, double width, double height) {
        super(colour);
        this.width = width;
        this.height = height;
    }

    @Override
    public double area() { return width * height; }

    @Override
    public double perimeter() { return 2 * (width + height); }
}

// Main class
public class ShapeDemo {
    public static void main(String[] args) {
        Shape[] shapes = {
            new Circle("Red", 5.0),
            new Rectangle("Blue", 4.0, 6.0),
            new Circle("Green", 3.0),
            new Rectangle("Yellow", 8.0, 2.0)
        };

        for (Shape s : shapes) {
            System.out.println(s); // polymorphic toString()
        }

        // Find largest area
        Shape largest = shapes[0];
        for (Shape s : shapes) {
            if (s.area() > largest.area()) largest = s;
        }
        System.out.println("\nLargest: " + largest);
    }
}

import java.util.*;
import java.util.stream.*;

public record Employee(int id, String name, String department, double salary) {}

public class EmployeeAnalytics {
    public static void main(String[] args) {
        List<Employee> employees = List.of(
            new Employee(1, "Alice",   "Engineering", 95000),
            new Employee(2, "Bob",     "Marketing",   65000),
            new Employee(3, "Charlie", "Engineering", 85000),
            new Employee(4, "Diana",   "HR",           55000),
            new Employee(5, "Eve",     "Engineering", 105000),
            new Employee(6, "Frank",   "Marketing",   72000),
            new Employee(7, "Grace",   "HR",           60000),
            new Employee(8, "Henry",   "Engineering", 78000)
        );

        // 1. Employees earning > $70,000
        System.out.println("=== Earning > $70,000 ===");
        employees.stream()
            .filter(e -> e.salary() > 70_000)
            .map(e -> e.name() + " ($" + e.salary() + ")")
            .forEach(System.out::println);

        // 2. Average salary by department
        System.out.println("\n=== Average salary by department ===");
        Map<String, Double> avgByDept = employees.stream()
            .collect(Collectors.groupingBy(
                Employee::department,
                Collectors.averagingDouble(Employee::salary)
            ));
        avgByDept.forEach((dept, avg) ->
            System.out.printf("%s: $%.2f%n", dept, avg));

        // 3. Top 3 highest paid
        System.out.println("\n=== Top 3 highest paid ===");
        employees.stream()
            .sorted(Comparator.comparingDouble(Employee::salary).reversed())
            .limit(3)
            .forEach(e -> System.out.println(e.name() + " - $" + e.salary()));

        // 4. Engineering names sorted
        System.out.println("\n=== Engineering (sorted) ===");
        List<String> engNames = employees.stream()
            .filter(e -> e.department().equals("Engineering"))
            .map(Employee::name)
            .sorted()
            .collect(Collectors.toList());
        System.out.println(engNames);

        // 5. Highest paid employee
        System.out.println("\n=== Highest paid ===");
        employees.stream()
            .max(Comparator.comparingDouble(Employee::salary))
            .ifPresent(e -> System.out.println(e.name() + " - $" + e.salary()));
    }
}

import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import java.util.*;

public class BankAccount {
    private final AtomicLong balance;
    private final String accountId;

    public BankAccount(String accountId, long initialBalance) {
        this.accountId = accountId;
        this.balance = new AtomicLong(initialBalance);
    }

    public void deposit(long amount) {
        if (amount <= 0) throw new IllegalArgumentException("Deposit must be positive");
        balance.addAndGet(amount);
    }

    // Thread-safe withdrawal using compare-and-set loop
    public boolean withdraw(long amount) {
        if (amount <= 0) throw new IllegalArgumentException("Withdrawal must be positive");
        long current;
        do {
            current = balance.get();
            if (current < amount) return false;  // insufficient funds
        } while (!balance.compareAndSet(current, current - amount));
        return true;
    }

    public long getBalance() { return balance.get(); }
    public String getAccountId() { return accountId; }
}

public class TransactionService implements AutoCloseable {
    private final ExecutorService pool;

    public TransactionService(int threads) {
        this.pool = Executors.newFixedThreadPool(threads);
    }

    public CompletableFuture<String> processDeposit(BankAccount account, long amount) {
        return CompletableFuture.supplyAsync(() -> {
            account.deposit(amount);
            return String.format("Deposited $%d → balance $%d [%s]",
                amount, account.getBalance(), Thread.currentThread().getName());
        }, pool).exceptionally(ex -> "Deposit failed: " + ex.getMessage());
    }

    public CompletableFuture<String> processWithdrawal(BankAccount account, long amount) {
        return CompletableFuture.supplyAsync(() -> {
            boolean success = account.withdraw(amount);
            return success
                ? String.format("Withdrew $%d → balance $%d [%s]",
                    amount, account.getBalance(), Thread.currentThread().getName())
                : String.format("Withdrawal of $%d FAILED — insufficient funds", amount);
        }, pool).exceptionally(ex -> "Withdrawal failed: " + ex.getMessage());
    }

    @Override
    public void close() throws Exception {
        pool.shutdown();
        pool.awaitTermination(10, TimeUnit.SECONDS);
    }
}

public class BankDemo {
    public static void main(String[] args) throws Exception {
        BankAccount account = new BankAccount("ACC-001", 1000L);
        System.out.println("Starting balance: $" + account.getBalance());

        try (TransactionService service = new TransactionService(4)) {
            List<CompletableFuture<String>> futures = new ArrayList<>();

            // 5 concurrent deposits of $200
            for (int i = 0; i < 5; i++) {
                futures.add(service.processDeposit(account, 200));
            }
            // 3 concurrent withdrawals of $400
            for (int i = 0; i < 3; i++) {
                futures.add(service.processWithdrawal(account, 400));
            }

            // Wait for all and collect results
            CompletableFuture.allOf(futures.toArray(new CompletableFuture[0]))
                .thenRun(() -> {
                    futures.forEach(f -> System.out.println(f.join()));
                    System.out.println("Final balance: $" + account.getBalance());
                })
                .get(); // block main thread
        }
    }
}

import java.util.*;

public final class HttpRequest {

    private static final Set<String> VALID_METHODS =
        Set.of("GET", "POST", "PUT", "DELETE", "PATCH");

    // All fields are final — immutable
    private final String url;
    private final String method;
    private final Map<String, String> headers;
    private final Optional<String> body;
    private final int timeoutMs;

    // Private constructor — only Builder can create instances
    private HttpRequest(Builder builder) {
        this.url       = builder.url;
        this.method    = builder.method;
        this.headers   = Collections.unmodifiableMap(new HashMap<>(builder.headers));
        this.body      = Optional.ofNullable(builder.body);
        this.timeoutMs = builder.timeoutMs;
    }

    // Getters only — no setters
    public String getUrl()            { return url; }
    public String getMethod()         { return method; }
    public Map<String, String> getHeaders() { return headers; }
    public Optional<String> getBody() { return body; }
    public int getTimeoutMs()         { return timeoutMs; }

    @Override
    public String toString() {
        return String.format(
            "HttpRequest{url='%s', method=%s, headers=%s, body=%s, timeout=%dms}",
            url, method, headers, body.orElse("(none)"), timeoutMs
        );
    }

    // Static inner Builder class
    public static class Builder {
        // Required
        private final String url;

        // Optional with defaults
        private String method  = "GET";
        private Map<String, String> headers = new HashMap<>();
        private String body    = null;
        private int timeoutMs  = 5000;

        public Builder(String url) {
            this.url = url;
        }

        public Builder method(String method) {
            this.method = method.toUpperCase();
            return this; // fluent — enables method chaining
        }

        public Builder addHeader(String key, String value) {
            this.headers.put(key, value);
            return this;
        }

        public Builder body(String body) {
            this.body = body;
            return this;
        }

        public Builder timeout(int timeoutMs) {
            this.timeoutMs = timeoutMs;
            return this;
        }

        public HttpRequest build() {
            // Validation
            if (url == null || url.isBlank()) {
                throw new IllegalArgumentException("URL must not be null or blank");
            }
            if (!VALID_METHODS.contains(method)) {
                throw new IllegalArgumentException(
                    "Invalid HTTP method: " + method +
                    ". Must be one of " + VALID_METHODS);
            }
            return new HttpRequest(this);
        }
    }

    // Demo
    public static void main(String[] args) {
        // Minimal GET request
        HttpRequest get = new HttpRequest.Builder("https://api.example.com/users")
            .build();
        System.out.println("GET Request:");
        System.out.println(get);

        // Full POST request
        HttpRequest post = new HttpRequest.Builder("https://api.example.com/users")
            .method("POST")
            .addHeader("Content-Type", "application/json")
            .addHeader("Authorization", "Bearer abc123")
            .body("{\"name\": \"Alice\", \"email\": \"alice@example.com\"}")
            .timeout(10000)
            .build();
        System.out.println("\nPOST Request:");
        System.out.println(post);

        // Invalid method — should throw
        try {
            HttpRequest invalid = new HttpRequest.Builder("https://api.example.com")
                .method("FETCH")
                .build();
        } catch (IllegalArgumentException e) {
            System.out.println("\nCaught expected: " + e.getMessage());
        }
    }
}

